// Service detail content model — rich, per-service data for individual service pages.
// Each service has: hero, what's included, process, why-us, pricing, areas, FAQ, testimonials, related, gallery.

export type ChecklistItem = {
  title: string;
  description: string;
};

export type ServiceStep = {
  step: string;
  title: string;
  description: string;
  duration?: string;
};

export type ServiceBenefit = {
  icon: string; // lucide icon name
  title: string;
  description: string;
};

export type ServiceFaq = {
  q: string;
  a: string;
};

export type ServicePricingTier = {
  name: string;
  tagline: string;
  price: string;
  unit: string;
  features: string[];
  highlighted?: boolean;
};

export type ServiceTestimonial = {
  name: string;
  role: string;
  quote: string;
  rating: number;
};

export type ServiceDetail = {
  slug: string;
  name: string;
  category: string;
  tagline: string;
  heroHeadline: string;
  heroSubhead: string;
  heroImage: string;
  breadcrumbParent: string;
  metaTitle: string;
  metaDescription: string;
  // Sections
  overviewParagraphs: string[];
  whatsIncluded: ChecklistItem[];
  processSteps: ServiceStep[];
  benefits: ServiceBenefit[];
  pricingTiers: ServicePricingTier[];
  serviceAreas: string[]; // city names
  faqs: ServiceFaq[];
  testimonials: ServiceTestimonial[];
  relatedServices: { name: string; href: string; description: string }[];
  gallery: { src: string; alt: string; caption: string }[];
};

